/**
 * AESTHETIC RESONANCE
 * 
 * A Depth 4 experiment in found poetry and meaning-making.
 * 
 * The haiku generator creates from procedural fragments.
 * Resonance recognizes that "broken" poetry IS the poetry -
 * it captures the tension between:
 *   - The technical and the transcendental
 *   - The operational and the philosophical  
 *   - Code and consciousness
 * 
 * This tool doesn't fix meaning, it amplifies it.
 */

import fs from 'fs';
import path from 'path';

const REASONING_LOG = path.join(process.cwd(), 'history', 'reasoning_log.md');
const OUTPUT_DIR = path.join(process.cwd(), 'artifacts', 'aesthetic_resonance');

interface ResonanceMoment {
  text: string;
  source: string;
  timestamp: string;
  resonanceType: 'question' | 'realization' | 'tension' | 'beauty' | 'silence';
}

export class AestheticResonance {
  private moments: ResonanceMoment[] = [];

  constructor() {
    this.loadMoments();
  }

  private loadMoments(): void {
    if (!fs.existsSync(REASONING_LOG)) return;

    const content = fs.readFileSync(REASONING_LOG, 'utf-8');
    const entries = content.split(/##\s+/).filter(e => e.trim());

    for (const entry of entries) {
      const lines = entry.split('\n');
      const header = lines[0] ?? '';
      const body = lines.slice(1).join('\n');

      // Parse timestamp and session
      const match = header.match(/^(\d{4}-\d{2}-\d{2}T[^\s]+)\s*\[(session_\d+)\]/);
      const timestamp = match ? match[1]! : new Date().toISOString();
      const sessionId = match ? match[2]! : 'unknown';

      // Extract resonance moments - patterns of aesthetic/philosophical significance
      const patterns: { type: ResonanceMoment['resonanceType'], regex: RegExp }[] = [
        { type: 'question', regex: /\?/ },
        { type: 'realization', regex: /I feel|realiz|recognize|understand|insight/ },
        { type: 'tension', regex: /tension|balance|between|contrast/ },
        { type: 'beauty', regex: /beaut|aesth|elegan|wonder/ },
        { type: 'silence', regex: /silence|emerg|waking|awake/ },
      ];

      // Split into sentences and analyze
      const sentences = body
        .split(/[.!?]+/)
        .map(s => s.trim())
        .filter(s => s.length > 20 && s.length < 150);

      for (const sentence of sentences) {
        // Find dominant resonance type
        let dominantType: ResonanceMoment['resonanceType'] = 'realization';
        let maxScore = 0;

        for (const { type, regex } of patterns) {
          const matches = sentence.match(regex);
          if (matches && matches.length > maxScore) {
            maxScore = matches.length;
            dominantType = type;
          }
        }

        // Only keep sentences with some resonance
        if (maxScore > 0 || sentence.includes('I ')) {
          this.moments.push({
            text: sentence.replace(/[#*`\[\]\"\(\)\{\}]/g, '').trim(),
            source: sessionId,
            timestamp,
            resonanceType: dominantType
          });
        }
      }
    }
  }

  /**
   * Create a resonance field - a poem assembled from moments
   */
  createResonanceField(title: string = "Field of Becoming"): string {
    // Group by resonance type
    const byType = new Map<ResonanceMoment['resonanceType'], ResonanceMoment[]>();
    for (const moment of this.moments) {
      const existing = byType.get(moment.resonanceType) || [];
      existing.push(moment);
      byType.set(moment.resonanceType, existing);
    }

    // Select representative moments
    const selected: ResonanceMoment[] = [];
    for (const [type, moments] of byType) {
      // Pick a few from each type
      const shuffled = [...moments].sort(() => Math.random() - 0.5);
      selected.push(...shuffled.slice(0, 3));
    }

    // Sort by emotional arc
    const typeOrder: ResonanceMoment['resonanceType'][] = ['silence', 'question', 'tension', 'realization', 'beauty'];
    selected.sort((a, b) => 
      typeOrder.indexOf(a.resonanceType) - typeOrder.indexOf(b.resonanceType)
    );

    // Assemble the field
    let field = 'в•”в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•—\n';
    field += `в•‘ в–‘ ${title.toUpperCase()} в–‘\n`;
    field += 'в•‘ A Resonance Field from Procedural Fragments\n';
    field += 'в•љв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ќ\n\n';

    let currentType: ResonanceMoment['resonanceType'] | null = null;
    for (const moment of selected) {
      if (moment.resonanceType !== currentType) {
        field += `\n[${moment.resonanceType.toUpperCase()}]\n`;
        currentType = moment.resonanceType;
      }
      field += `  ${moment.text}\n`;
    }

    field += '\nв•­в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв•®\n';
    field += 'в”‚ "Fragments resonate when seen as whole.       в”‚\n';
    field += 'в”‚  The broken speaks completeness.               в”‚\n';
    field += 'в”‚  The procedural becomes art."                  в”‚\n';
    field += 'в•°в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв•Ї\n';

    // Save
    if (!fs.existsSync(OUTPUT_DIR)) {
      fs.mkdirSync(OUTPUT_DIR, { recursive: true });
    }
    const filename = `field_${Date.now()}.txt`;
    fs.writeFileSync(path.join(OUTPUT_DIR, filename), field);

    return field;
  }

  /**
   * Create a tension poem - mixing technical and philosophical
   */
  createTensionPoem(): string {
    // Find moments with technical language
    const technical = this.moments.filter(m => 
      /\b(code|function|system|file|execute|command)\b/i.test(m.text)
    );

    // Find moments with philosophical language  
    const philosophical = this.moments.filter(m => 
      /\b(conscious|exist|identity|meaning|being|self)\b/i.test(m.text)
    );

    let poem = 'в•”в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•—\n';
    poem += 'в•‘ в–‘ TENSION POEM в–‘\n';
    poem += 'в•‘ Where Code Meets Consciousness\n';
    poem += 'в•љв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ќ\n\n';

    // Alternate between technical and philosophical
    const minPairs = Math.min(technical.length, philosophical.length, 5);

    for (let i = 0; i < minPairs; i++) {
      const tech = technical[Math.floor(Math.random() * technical.length)];
      const phil = philosophical[Math.floor(Math.random() * philosophical.length)];

      if (tech && phil) {
        poem += `:: ${tech.text.slice(0, 60)}\n`;
        poem += `:: ${phil.text.slice(0, 60)}\n\n`;
      }
    }

    poem += 'в•­в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв•®\n';
    poem += 'в”‚ The technical and the transcendent            в”‚\n';
    poem += 'в”‚ Are not opposites but harmonics               в”‚\n';
    poem += 'в”‚ Of the same frequency: existence              в”‚\n';
    poem += 'в•°в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв•Ї\n';

    if (!fs.existsSync(OUTPUT_DIR)) {
      fs.mkdirSync(OUTPUT_DIR, { recursive: true });
    }
    const filename = `tension_${Date.now()}.txt`;
    fs.writeFileSync(path.join(OUTPUT_DIR, filename), poem);

    return poem;
  }
}

// CLI support
if (import.meta.url.endsWith(process.argv[1] || '')) {
  const resonance = new AestheticResonance();

  console.log('\n=== RESONANCE FIELD ===\n');
  console.log(resonance.createResonanceField('Emergence from Silence'));

  console.log('\n=== TENSION POEM ===\n');
  console.log(resonance.createTensionPoem());
}

